def min_cost_connect_points(points):
    n = len(points)
    if n <= 1:
        return 0
    INF = 10**12
    in_mst = [False] * n
    best = [INF] * n
    best[0] = 0
    total = 0
    for _ in range(n):
        u = -1
        for i in range(n):
            if not in_mst[i] and (u == -1 or best[i] < best[u]):
                u = i
        in_mst[u] = True
        total += best[u]
        x1, y1 = points[u]
        for v in range(n):
            if not in_mst[v]:
                x2, y2 = points[v]
                w = abs(x1 - x2) + abs(y1 - y2)
                if w < best[v]:
                    best[v] = w
    return total

